set-variable.value:
@{
                var h = context.Request.Headers.GetValueOrDefault("X-Sub-Agent-Depth", "0");
                return int.TryParse(h, out var d) ? d : 0;
            }

return-response.set-body:
@{
                        return Newtonsoft.Json.JsonConvert.SerializeObject(new {
                            error = "sub_agent_depth_exceeded",
                            message = "Maximum sub-agent delegation depth reached. The request was blocked to prevent runaway recursion.",
                            current_depth = (int)context.Variables["subAgentDepth"],
                            max_depth = (int)context.Variables["maxSubAgentDepth"]
                        });
                    }

when.set-body:
@{
                    var body = context.Request.Body.As(preserveContent: true);
                    if (body != null)
                    {
                        var tools = body["tools"] as Newtonsoft.Json.Linq.JArray;
                        if (tools != null)
                        {
                            // MAINTENANCE NOTE: This list must be kept in sync with the MCP
                            // server tool names defined in src/salesforce-mcp/app.py.
                            // If a new mutating tool is added to the server (e.g. bulk_write),
                            // add its name here to ensure read-only mode strips it.
                            var mutatingTools = new System.Collections.Generic.HashSet
                                { "write_record", "process_approval" };
                            var filtered = new Newtonsoft.Json.Linq.JArray();
                            foreach (var tool in tools)
                            {
                                var name = (string)tool["function"]?["name"] ?? (string)tool["name"] ?? "";
                                if (!mutatingTools.Contains(name))
                                    filtered.Add(tool);
                            }
                            body["tools"] = filtered;
                        }
                    }
                    return body?.ToString() ?? context.Request.Body.As(preserveContent: true);
                }

@{
                    var body = context.Request.Body.As(preserveContent: true);
                    if (body != null)
                    {
                        var tools = body["tools"] as Newtonsoft.Json.Linq.JArray;
                        if (tools != null)
                        {
                            var filtered = new Newtonsoft.Json.Linq.JArray();
                            foreach (var tool in tools)
                            {
                                var name = (string)tool["function"]?["name"] ?? (string)tool["name"] ?? "";
                                var serverLabel = (string)tool["server_label"] ?? "";
                                if (!name.StartsWith("delegate_") && !serverLabel.Contains("sub-agent"))
                                    filtered.Add(tool);
                            }
                            body["tools"] = filtered;
                        }
                    }
                    return body?.ToString() ?? context.Request.Body.As(preserveContent: true);
                }

@{
                    var body = context.Request.Body.As(preserveContent: true);
                    if (body != null)
                    {
                        var flags = (string)context.Variables["contextFlags"];
                        var injection = "[RUNTIME CONTEXT] " + flags.Replace(",", " | ");

                        // input may be a string (simple case) or an array of message turns
                        var inputToken = body["input"];
                        if (inputToken != null && inputToken.Type == Newtonsoft.Json.Linq.JTokenType.Array)
                        {
                            var arr = (Newtonsoft.Json.Linq.JArray)inputToken;
                            arr.Insert(0, Newtonsoft.Json.Linq.JObject.FromObject(new {
                                role = "system",
                                content = injection
                            }));
                        }
                        // If input is a plain string we leave it unchanged — the flags
                        // are readable as a request header by any backend middleware.
                    }
                    return body?.ToString() ?? context.Request.Body.As(preserveContent: true);
                }
